/*===================================================================================================================================*/
/*  void    vd_g_MemfillU4(U4 * u4_ap_buff, const U4 u4_a_FILL, const U4 u4_a_NUM_WORD)                                              */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      -                                                                                                                */
/*  Return:         -                                                                                                                */
/*===================================================================================================================================*/
void    vd_g_MemfillU4(U4 * u4_ap_buff, const U4 u4_a_FILL, const U4 u4_a_NUM_WORD)
{
    U4         u4_t_cnt;

    for(u4_t_cnt = (U4)0U; u4_t_cnt < u4_a_NUM_WORD; u4_t_cnt++){
        u4_ap_buff[u4_t_cnt] = u4_a_FILL;
    }
}
